package com.taxin60sec.backend.controller;
import com.taxin60sec.backend.payment.PaymentService;
import lombok.RequiredArgsConstructor;
import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/payments") @RequiredArgsConstructor public class PaymentController {private final PaymentService payments;@PostMapping("/orders")public PaymentService.PaymentOrder order(@RequestBody PaymentService.PaymentOrderRequest request){return payments.createOrder(request);}@PostMapping("/webhooks/{provider}")public PaymentService.PaymentEvent webhook(@PathVariable String provider,@RequestBody String payload,@RequestHeader(value="X-Razorpay-Signature",required=false)String signature,@RequestHeader java.util.Map<String,String> headers){return payments.verifyWebhook(new PaymentService.PaymentWebhook(provider,payload,signature,headers));}@PostMapping("/{paymentId}/refunds")public PaymentService.Refund refund(@PathVariable String paymentId,@RequestBody PaymentService.RefundRequest request){return payments.refund(new PaymentService.RefundRequest(paymentId,request.amount(),request.reason()));}@GetMapping("/{paymentId}/invoice")public PaymentService.Invoice invoice(@PathVariable String paymentId){return payments.invoice(paymentId);}}
